19→class PostListButton : LinearLayout {
20→    private lateinit var imageView: ImageView
21→    private lateinit var textView: TextView
22→    var buttonType: PostListButtonType? = null
23→        private set
24→
25→    constructor(context: Context) : super(context) {
26→        initView(context, null)
27→    }
28→
29→    constructor(context: Context, attrs: AttributeSet) : super(context, attrs) {
30→        initView(context, attrs)
31→    }
32→
33→    constructor(context: Context, attrs: AttributeSet, defStyle: Int) : super(context, attrs, defStyle) {
34→        initView(context, attrs)
35→    }
36→
37→    private fun initView(context: Context, attrs: AttributeSet?) {
38→        View.inflate(context, R.layout.post_list_button, this)
39→
40→        imageView = findViewById(R.id.image)
41→        textView = findViewById(R.id.text)
42→
43→        var buttonType = 0
44→        if (attrs != null) {
45→            val a = context.theme.obtainStyledAttributes(
46→                attrs,
47→                R.styleable.wpPostListButton,
48→                0, 0
49→            )
50→            try {
51→                buttonType = a.getInteger(R.styleable.wpPostListButton_wpPostButtonType, 0)
52→            } finally {
53→                a.recycle()
54→            }
55→        }
56→
57→        if (buttonType != 0) {
58→            setButtonType(buttonType)
59→        }
60→    }
61→
62→    @Suppress("MemberVisibilityCanBePrivate", "UseCheckOrError")
63→    fun setButtonType(buttonTypeInt: Int) {
64→        if (buttonTypeInt == this.buttonType?.value) {
65→            return
66→        }
67→        val nullableType = PostListButtonType.fromInt(buttonTypeInt)
68→        nullableType?.let {
69→            updateButtonType(nullableType)
70→        } ?: if (BuildConfig.DEBUG) {
71→            throw IllegalStateException("Unknown button type id: $buttonTypeInt")
72→        } else {
73→            AppLog.e(AppLog.T.POSTS, "PostListButton.setButtonType called from xml with an unknown buttonType.")
74→        }
75→    }
76→
77→    fun updateButtonType(buttonType: PostListButtonType) {
78→        if (buttonType === this.buttonType) {
79→            return
80→        }
81→        this.buttonType = buttonType
82→        loadResourcesForButtonType(buttonType)
83→    }
84→
85→    private fun loadResourcesForButtonType(buttonType: PostListButtonType) {
86→        val color = context.getColorFromAttribute(buttonType.colorAttrId)
87→        ColorUtils.setImageResourceWithTint(
88→            imageView,
89→            buttonType.iconResId,
90→            context.getColorResIdFromAttribute(buttonType.colorAttrId)
91→        )
92→        textView.setText(buttonType.textResId)
93→        textView.setTextColor(color)
94→    }
95→}
