    private fun orderButtonTypes(
        postStatus: PostStatus,
        buttonTypes: List<PostListButtonType>
    ): List<PostListButtonType> {
        val primaryOrder = when (postStatus) {
            TRASHED -> listOf(BUTTON_MOVE_TO_DRAFT)
            PUBLISHED -> listOf(BUTTON_VIEW, BUTTON_STATS, BUTTON_EDIT)
            else -> listOf(BUTTON_EDIT)
        }
        val publishOrder = listOf(BUTTON_RETRY, BUTTON_SYNC, BUTTON_PUBLISH, BUTTON_SUBMIT)
        val viewOrder = listOf(BUTTON_PREVIEW, BUTTON_VIEW, BUTTON_STATS)
        val manageOrder = listOf(
            BUTTON_COPY,
            BUTTON_COPY_URL,
            BUTTON_PROMOTE_WITH_BLAZE,
            BUTTON_MOVE_TO_DRAFT
        )
        val offlineOrder = listOf(BUTTON_CANCEL_PENDING_AUTO_UPLOAD)
        val destructiveOrder = listOf(BUTTON_TRASH, BUTTON_DELETE, BUTTON_DELETE_PERMANENTLY)
        val fullOrder = buildList {
            addAll(primaryOrder)
            addAll(publishOrder)
            addAll(viewOrder)
            addAll(manageOrder)
            addAll(offlineOrder)
            addAll(destructiveOrder)
        }
        val orderIndex = fullOrder.withIndex().associate { it.value to it.index }

        return buttonTypes.sortedBy { orderIndex[it] ?: Int.MAX_VALUE }
    }

